#include <math.h>

void rgb_to_hsi(int r, int g, int b, double* h, double* s, double* i) {
 *i = (r + g + b) / 3.0;
 *s = 1 - (double)min(r, min(g, b)) / *i;
 if (b <= g) {
 *h = acos(((r-g)+(r-b)) / (2*sqrt((r-g)*(r-g) + (r-b)*(g-b))));
 } else {
 *h = 360 - acos(((r-g)+(r-b)) / (2*sqrt((r-g)*(r-g) + (r-b)*(g-b))));
 }
}

int main() {
 int r = 255, g = 0, b = 0; // Red color
 double h, s, i;
 rgb_to_hsi(r, g, b, &h, &s, &i);
 printf("Hue: %.2f, Saturation: %.2f, Intensity: %.2f\n", h, s, i);
 return 0;
}
